const crypto = require('crypto');
const secret = $env.N8N_HMAC_SECRET;
if (!secret) { throw new Error('N8N_HMAC_SECRET is not set'); }
const header = $input.item.json.headers['x-lumivara-signature'] || '';
const raw = ($input.item.binary && $input.item.binary.data && Buffer.from($input.item.binary.data.data, 'base64').toString('utf8')) || $input.item.json.rawBody || JSON.stringify($input.item.json.body || {});
const parts = Object.fromEntries(header.split(',').map(s => s.split('=', 2).map(x => x && x.trim())));
const ts = Number(parts.t);
const sent = parts.v1 || '';
if (!Number.isFinite(ts) || !sent) { throw new Error('malformed signature'); }
const nowSec = Math.floor(Date.now() / 1000);
if (Math.abs(nowSec - ts) > 300) { throw new Error('stale signature'); }
const expected = crypto.createHmac('sha256', secret).update(`${ts}.${raw}`).digest('hex');
const a = Buffer.from(expected, 'hex');
const b = Buffer.from(sent, 'hex');
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) { throw new Error('signature mismatch'); }
const payload = JSON.parse(raw);
return [{ json: { ...payload, _verifiedAt: new Date().toISOString() } }];

