const crypto = require('crypto');
const secret = $env['N8N_HMAC_SECRET'];
const header = $input.first().headers['x-lumivara-signature'] || '';
const raw = $input.first().rawBody?.toString('utf8') ?? '';
const parts = Object.fromEntries(header.split(',').map(p => p.split('=')));
const t = Number(parts.t);
const supplied = parts.v1;
if (!Number.isFinite(t) || !supplied) throw new Error('bad-signature-format');
if (Math.abs(Math.floor(Date.now() / 1000) - t) > 300) throw new Error('signature-stale');
const expected = crypto.createHmac('sha256', secret).update(`${t}.${raw}`).digest('hex');
const a = Buffer.from(expected, 'hex');
const b = Buffer.from(supplied, 'hex');
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) throw new Error('signature-invalid');
return [{ json: JSON.parse(raw) }];
